import { useCallback, useEffect, useImperativeHandle, useState } from "react";
import type { IListItem } from "@lmb-it/kitsconcerto-types";
import { useSelect } from "../SelectContext";

export interface AutoCompleteLogicProps {
    isMultiple?: boolean;
    forceSelection?: boolean;
    completeMethod?: (query: string) => void | Promise<any>;
    ref?: any;
}

/**
 * Shared logic for AutoComplete web & native.
 *
 * Provides: filterValue, handleOnChange, search, makeFallback,
 * inputValue/filteredList state, and selectedValue sync.
 */
export const useAutoCompleteLogic = (props: AutoCompleteLogicProps) => {
    const { isMultiple, forceSelection, completeMethod, ref } = props;

    const {
        list,
        childrenKey,
        labelKey,
        valueKey,
        outputValueKey,
        onChange,
        selectedValue,
    } = useSelect();

    const isAll = outputValueKey === "*";

    const [inputValue, setInputValue] = useState<
        string | string[] | Record<string, any> | null
    >(null);

    const [filteredList, setFilteredList] = useState<IListItem[] | null>(null);

    useImperativeHandle(ref, () => ({}));

    /* ─── Value extraction ───────────────────────────── */

    const filterValue = useCallback(
        (incomingValue: any) => {
            if (isAll) return incomingValue;
            if (Array.isArray(incomingValue) && !isMultiple) {
                if (incomingValue.length === 0) return null;
            }
            if (incomingValue != null && typeof incomingValue === "object") {
                if (outputValueKey in incomingValue) {
                    return incomingValue[outputValueKey];
                }
                if (valueKey in incomingValue) {
                    return incomingValue[valueKey];
                }
            }
            return incomingValue;
        },
        [isAll, isMultiple, outputValueKey, valueKey],
    );

    /* ─── onChange handler ────────────────────────────── */

    const handleOnChange = useCallback(
        (event: { originalEvent?: any; value: any }) => {
            let value: any = undefined;

            if (isMultiple) {
                if (Array.isArray(event.value)) {
                    value = isAll
                        ? event.value
                        : event.value.map((item: any) => filterValue(item));
                } else {
                }
            } else {
                const item = event.value;
                if (item == null) {
                    value = null;
                } else if (typeof item !== "string") {
                    value = filterValue(item);
                } else {
                    value = item;
                }
            }

            if (value !== undefined) {
                onChange(
                    {
                        target: { value },
                        originalEvent: event.originalEvent,
                    },
                    event.value,
                );
            } else {
            }
        },
        [isMultiple, isAll, onChange, filterValue],
    );

    /* ─── Sync selectedValue → inputValue ────────────── */

    useEffect(() => {
        if (isMultiple) {
            if (Array.isArray(selectedValue) && selectedValue.length > 0) {
                if (selectedValue.every((v: any) => typeof v === "object")) {
                    setInputValue(selectedValue);
                } else {
                    const mapped = selectedValue.map((v: any) => {
                        if (typeof v === "string") {
                            const found = list?.find((item: any) => item[valueKey] === v);
                            return found ?? { [labelKey]: v, [valueKey]: v };
                        }
                        return v;
                    });
                    setInputValue(mapped);
                }
            } else {
                setInputValue(null);
            }
        } else {
            if (selectedValue != null && typeof selectedValue === "object") {
                // Keep the full object so Core/PrimeReact can resolve the label via field prop
                setInputValue(selectedValue);
            } else if (typeof selectedValue === "string") {
                setInputValue(selectedValue);
            } else if (selectedValue == null) {
                setInputValue(null);
            }
        }
    }, [selectedValue, labelKey, valueKey, isMultiple, list]);

    /* ─── Fallback creation ──────────────────────────── */

    const makeFallback = useCallback(
        (query: string): IListItem[] => {
            if (childrenKey) {
                return [
                    {
                        [labelKey]: "_",
                        [childrenKey]: [
                            { [labelKey]: query, [valueKey]: query },
                        ],
                    },
                ];
            }
            return [{ [labelKey]: query, [valueKey]: query }];
        },
        [labelKey, valueKey, childrenKey],
    );

    /* ─── Search callback ────────────────────────────── */

    const search = useCallback(
        (event: { originalEvent?: any; query: string }) => {

            if (completeMethod && typeof completeMethod === "function") {
                const res = completeMethod(event.query);
                const fallback = !forceSelection ? makeFallback(event.query) : [];
                if (res instanceof Promise) {
                    res.then((response) => {
                        if (Array.isArray(response)) {
                            setFilteredList(
                                response.length > 0
                                    ? (response as IListItem[])
                                    : fallback,
                            );
                        } else if (
                            response?.data &&
                            Array.isArray(response.data)
                        ) {
                            setFilteredList(
                                response.data.length > 0
                                    ? (response.data as IListItem[])
                                    : fallback,
                            );
                        } else {
                            setFilteredList(fallback);
                        }
                    });
                } else {
                    setFilteredList((res as unknown as IListItem[] | null) ?? null);
                }
            } else {
                // Client-side filtering
                if (!Array.isArray(list)) return;
                const input = event.query;
                if (!input.trim().length) {
                    setFilteredList([...list]);
                } else {
                    let filtered: any[];
                    if (childrenKey) {
                        filtered = [];
                        for (const group of list) {
                            const children = (group as any)[childrenKey];
                            const matchedChildren =
                                Array.isArray(children) &&
                                children.filter((item: any) => {
                                    const val = item[labelKey] ?? item[valueKey];
                                    return String(val)
                                        .toLowerCase()
                                        .startsWith(input.toLowerCase());
                                });
                            if (matchedChildren && matchedChildren.length) {
                                filtered.push({
                                    ...group,
                                    [childrenKey]: matchedChildren,
                                });
                            }
                        }
                    } else {
                        filtered = list.filter((item: any) => {
                            const val = item[labelKey] ?? item[valueKey];
                            return String(val)
                                .toLowerCase()
                                .startsWith(input.toLowerCase());
                        });
                    }

                    if (filtered.length === 0 && !forceSelection) {
                        setFilteredList(makeFallback(input));
                    } else {
                        setFilteredList(filtered);
                    }
                }
            }
        },
        [completeMethod, list, childrenKey, labelKey, valueKey, forceSelection, makeFallback],
    );

    return {
        // State
        inputValue,
        setInputValue,
        filteredList,
        setFilteredList,
        // Computed
        isAll,
        // Callbacks
        filterValue,
        handleOnChange,
        search,
        makeFallback,
        // Context values
        list,
        childrenKey,
        labelKey,
        valueKey,
        outputValueKey,
        onChange,
        selectedValue,
    };
};
